(() => {
  const canvas = document.getElementById('preview-canvas');
  const ctx = canvas.getContext('2d');
  const W = 450, H = 600;
  canvas.width = W;
  canvas.height = H;

const BUBBLE_DATA_URL = 'data:image/png;base64,';

  let bubbleImg = new Image();
  bubbleImg.src = BUBBLE_DATA_URL;
  let userImg = null;
  let bubbleX = W * 0.75, bubbleY = H * 0.2;
  
  const BASE_BUBBLE_WIDTH = 400;
  let imgOffsetX = 0, imgOffsetY = 0;
  let isDraggingImg = false;
  let dragStartX, dragStartY, dragOffsetStartX, dragOffsetStartY;

  const slider = document.getElementById('size-slider');
  const textInput = document.getElementById('text-input');
  const fileInput = document.getElementById('file-input');
  const saveBtn = document.getElementById('save-btn');
  const imgSlider = document.getElementById('img-slider');


  function getBubbleSize() {
    const s = parseFloat(slider.value);
    const w = BASE_BUBBLE_WIDTH * s;
    const h = (w * bubbleImg.height) / bubbleImg.width;
    return { w, h, s };
  }

  function drawUserImage(frameX, frameY, frameW, frameH) {
    if (!userImg) return;
    const scale = parseFloat(imgSlider.value);
    const ir = userImg.width / userImg.height;
    const br = frameW / frameH;
    let dw, dh;
    if (ir > br) { dh = frameH * scale; dw = dh * ir; }
    else { dw = frameW * scale; dh = dw / ir; }
    const dx = frameX + (frameW - dw) / 2 + imgOffsetX;
    const dy = frameY + (frameH - dh) / 2 + imgOffsetY;
    ctx.drawImage(userImg, dx, dy, dw, dh);
  }

  function render() {
    ctx.clearRect(0, 0, W, H);

    const padding = 24;
    const titleBar = 40;
    const frameX = Math.round(padding * W / canvas.offsetWidth);
    const frameY = Math.round((padding + titleBar) * H / canvas.offsetHeight);
    const frameBottom = Math.round(padding * H / canvas.offsetHeight);
    const frameW = W - 2 * frameX;
    const frameH = H - frameY - frameBottom;

    ctx.save();
    ctx.beginPath();
    const r = 8;
    ctx.moveTo(frameX, frameY);
    ctx.lineTo(frameX + frameW, frameY);
    ctx.lineTo(frameX + frameW, frameY + frameH - r);
    ctx.arcTo(frameX + frameW, frameY + frameH, frameX + frameW - r, frameY + frameH, r);
    ctx.lineTo(frameX + r, frameY + frameH);
    ctx.arcTo(frameX, frameY + frameH, frameX, frameY + frameH - r, r);
    ctx.closePath();
    ctx.clip();
    drawUserImage(frameX, frameY, frameW, frameH);
    ctx.restore();

    const { w: bw, h: bh, s: bs } = getBubbleSize();
    bubbleX = W - bw / 2;
    bubbleY = bh / 2;
    ctx.drawImage(bubbleImg, bubbleX - bw / 2, bubbleY - bh / 2, bw, bh);

    const txt = textInput.value;
    if (txt) {
      ctx.save();
      ctx.fillStyle = '#3c73b5';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'top';

      const maxW = 120 * bs;
      const maxH = 80 * bs;
      const minFont = 8 * bs;
      const maxFont = 24 * bs;
      const lineGap = 1.35;

      const ox = 220 - W / 2;
      const oy = 230 - H / 2;
      const ax = bubbleX + ox * bs;
      const ay = bubbleY + oy * bs;

      ctx.translate(ax, ay);
      ctx.rotate(-40 * Math.PI / 180);

      function measure(fontSize) {
        ctx.font = `bold ${fontSize}px sans-serif`;
        const lines = [];
        const paras = txt.split('\n');
        for (const p of paras) {
          if (p === '') { lines.push(''); continue; }
          let line = '';
          for (let j = 0; j < p.length; j++) {
            const ch = p[j];
            if (ctx.measureText(line + ch).width > maxW && line) {
              lines.push(line);
              line = ch;
            } else {
              line += ch;
            }
          }
          if (line) lines.push(line);
        }
        return lines;
      }

      function totalH(lines, fontSize) {
        return lines.length * fontSize * lineGap;
      }

      let fontSize = maxFont;
      let lines = measure(fontSize);

      if (lines.length === 1 && ctx.measureText(lines[0]).width <= maxW) {
        fontSize = Math.min(maxFont, maxW * 0.85 / ctx.measureText(lines[0]).width * fontSize);
        fontSize = Math.max(minFont, Math.min(maxFont, fontSize));
        ctx.font = `bold ${fontSize}px sans-serif`;
        ctx.fillText(lines[0], 0, -fontSize / 2);
      } else {
        while (fontSize > minFont && totalH(lines, fontSize) > maxH) {
          fontSize -= 1 * bs;
          lines = measure(fontSize);
        }
        ctx.font = `bold ${fontSize}px sans-serif`;
        const th = totalH(lines, fontSize);
        const startY = -th / 2;
        for (let i = 0; i < lines.length; i++) {
          if (lines[i] !== '') {
            ctx.fillText(lines[i], 0, startY + i * fontSize * lineGap);
          }
        }
      }

      ctx.restore();
    }


  }

  bubbleImg.onload = render;
  slider.addEventListener('input', render);
  imgSlider.addEventListener('input', render);
  textInput.addEventListener('input', render);

  fileInput.addEventListener('change', e => {
    const f = e.target.files[0];
    if (!f) return;
    if (!f.type.startsWith('image/')) { alert('请选择图片文件！'); return; }
    const img = new Image();
    img.onload = () => { userImg = img; imgOffsetX = 0; imgOffsetY = 0; imgSlider.value = 1; render(); };
    img.src = URL.createObjectURL(f);
  });

  function getPos(e) {
    const r = canvas.getBoundingClientRect();
    const scaleX = W / r.width, scaleY = H / r.height;
    const ev = e.touches ? e.touches[0] : e;
    return { x: (ev.clientX - r.left) * scaleX, y: (ev.clientY - r.top) * scaleY };
  }

  function onDown(e) {
    if (!userImg) return;
    const p = getPos(e);
    const padding = 24;
    const titleBar = 40;
    const frameX = Math.round(padding * W / canvas.offsetWidth);
    const frameY = Math.round((padding + titleBar) * H / canvas.offsetHeight);
    const frameBottom = Math.round(padding * H / canvas.offsetHeight);
    const frameW = W - 2 * frameX;
    const frameH = H - frameY - frameBottom;
    if (p.x >= frameX && p.x <= frameX + frameW && p.y >= frameY && p.y <= frameY + frameH) {
      isDraggingImg = true;
      dragStartX = p.x; dragStartY = p.y;
      dragOffsetStartX = imgOffsetX; dragOffsetStartY = imgOffsetY;
      e.preventDefault();
    }
  }

  function onMove(e) {
    if (!isDraggingImg) return;
    const p = getPos(e);
    imgOffsetX = dragOffsetStartX + (p.x - dragStartX);
    imgOffsetY = dragOffsetStartY + (p.y - dragStartY);
    render();
    e.preventDefault();
  }

  function onUp() { isDraggingImg = false; }

  canvas.addEventListener('mousedown', onDown);
  canvas.addEventListener('mousemove', onMove);
  canvas.addEventListener('mouseup', onUp);
  canvas.addEventListener('mouseleave', onUp);
  canvas.addEventListener('touchstart', onDown, { passive: false });
  canvas.addEventListener('touchmove', onMove, { passive: false });
  canvas.addEventListener('touchend', onUp);

  saveBtn.addEventListener('click', () => {
    try {
      canvas.toBlob(blob => {
        if (!blob) { alert('保存失败，请重试'); return; }
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.download = 'my_design.png';
        a.href = url;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        setTimeout(() => URL.revokeObjectURL(url), 1000);
      }, 'image/png');
    } catch (e) {
      alert('保存失败：' + e.message);
    }
  });
})();
